// Dafny port of src/collections/linear_fifo.rs
//
// Rust-faithful intent: this keeps the same FIFO state (`buf`, `head`, `count`)
// and the same observable circular-buffer operations.  Dafny has no Rust slice
// borrowing, MaybeUninit, allocator trait dispatch, or by-reference writable
// slice API, so those Rust primitives are represented mechanically with a
// sequence-backed buffer plus small helper methods.

module LinearFifoPort {
  class LinearFifo<T(0)> {
    var buf: seq<T>
    var head: int
    var count: int
    var dynamic: bool
    var powers_of_two: bool

    predicate Valid()
      reads this
    {
      0 <= count <= |buf| &&
      0 <= head &&
      (|buf| == 0 ==> head == 0) &&
      (|buf| > 0 ==> head < |buf|)
    }

    constructor Init(capacity: nat, dynamic_: bool, powers_of_two_: bool)
      ensures Valid()
      ensures |buf| == capacity
      ensures head == 0 && count == 0
    {
      buf := seq(capacity, _ => default(T));
      head := 0;
      count := 0;
      dynamic := dynamic_;
      powers_of_two := powers_of_two_;
    }

    function method capacity(): int
      reads this
      requires Valid()
    {
      |buf|
    }

    function method readable_length(): int
      reads this
      requires Valid()
    {
      count
    }

    function method writable_length(): int
      reads this
      requires Valid()
    {
      |buf| - count
    }

    function method Wrap(idx: int): int
      reads this
      requires Valid()
      requires 0 <= idx
    {
      if |buf| == 0 then 0 else idx % |buf|
    }

    function method ReadableModel(): seq<T>
      reads this
      requires Valid()
      decreases count
    {
      if count == 0 then []
      else [buf[head]] + ReadableFrom(Wrap(head + 1), count - 1)
    }

    function method ReadableFrom(pos: int, n: int): seq<T>
      reads this
      requires Valid()
      requires 0 <= n <= count
      requires n == 0 || |buf| > 0
      requires n == 0 || 0 <= pos < |buf|
      decreases n
    {
      if n == 0 then []
      else [buf[pos]] + ReadableFrom(Wrap(pos + 1), n - 1)
    }

    function method Fill(n: int): seq<T>
      requires 0 <= n
    {
      seq(n, _ => default(T))
    }

    method reset_head_if_empty()
      requires Valid()
      modifies this
      ensures Valid()
      ensures count == old(count)
      ensures |buf| == old(|buf|)
      ensures count == 0 ==> head == 0
    {
      if count == 0 {
        head := 0;
      }
    }

    method realign()
      requires Valid()
      modifies this
      ensures Valid()
      ensures head == 0
      ensures count == old(count)
      ensures |buf| == old(|buf|)
      ensures ReadableModel() == old(ReadableModel())
    {
      var r := ReadableModel();
      buf := r + Fill(|buf| - |r|);
      head := 0;
      count := |r|;
    }

    method shrink(size: nat)
      requires Valid()
      requires size >= count
      modifies this
      ensures Valid()
      ensures count == old(count)
      ensures ReadableModel() == old(ReadableModel())
      ensures dynamic ==> |buf| == size
      ensures !dynamic ==> |buf| == old(|buf|)
    {
      if dynamic {
        var r := ReadableModel();
        buf := r + Fill(size - |r|);
        head := 0;
        count := |r|;
      }
    }

    method ensure_total_capacity(size: nat) returns (ok: bool)
      requires Valid()
      modifies this
      ensures Valid()
      ensures count == old(count)
      ensures ReadableModel() == old(ReadableModel())
      ensures ok ==> |buf| >= size
      ensures !ok ==> !dynamic && old(|buf|) < size
    {
      if |buf| >= size {
        ok := true;
        return;
      }
      if dynamic {
        var r := ReadableModel();
        buf := r + Fill(size - |r|);
        head := 0;
        count := |r|;
        ok := true;
      } else {
        ok := false;
      }
    }

    method ensure_unused_capacity(size: nat) returns (ok: bool)
      requires Valid()
      modifies this
      ensures Valid()
      ensures count == old(count)
      ensures ReadableModel() == old(ReadableModel())
      ensures ok ==> writable_length() >= size
    {
      if writable_length() >= size {
        ok := true;
      } else {
        ok := ensure_total_capacity(count + size);
      }
    }

    method readable_slice(offset: nat) returns (s: seq<T>)
      requires Valid()
      ensures Valid()
      ensures offset > old(count) ==> s == []
      ensures offset <= old(count) ==> s == old(ReadableModel())[offset..]
    {
      if offset > count {
        s := [];
      } else {
        s := ReadableModel()[offset..];
      }
    }

    method discard(n: nat)
      requires Valid()
      requires n <= count
      modifies this
      ensures Valid()
      ensures count == old(count) - n
      ensures ReadableModel() == old(ReadableModel())[n..]
    {
      if |buf| == 0 {
        head := 0;
      } else {
        head := (head + n) % |buf|;
      }
      count := count - n;
      if count == 0 && |buf| == 0 {
        head := 0;
      }
    }

    method read_item() returns (ok: bool, item: T)
      requires Valid()
      modifies this
      ensures Valid()
      ensures old(count) == 0 ==> !ok
      ensures old(count) > 0 ==> ok && item == old(ReadableModel())[0]
      ensures old(count) > 0 ==> ReadableModel() == old(ReadableModel())[1..]
    {
      if count == 0 {
        ok := false;
        item := default(T);
        return;
      }
      item := buf[head];
      discard(1);
      ok := true;
    }

    method read(max: nat) returns (out: seq<T>)
      requires Valid()
      modifies this
      ensures Valid()
      ensures |out| <= max
      ensures out == old(ReadableModel())[..|out|]
      ensures ReadableModel() == old(ReadableModel())[|out|..]
    {
      var n := if max <= count then max else count;
      out := ReadableModel()[..n];
      discard(n);
    }

    method writable_slice_len(offset: nat) returns (n: nat)
      requires Valid()
      ensures n <= writable_length()
    {
      if offset > |buf| || offset > writable_length() {
        n := 0;
        return;
      }
      var tail := head + offset + count;
      if tail < |buf| {
        n := |buf| - tail;
      } else if |buf| == 0 {
        n := 0;
      } else {
        var start := tail - |buf|;
        n := writable_length() - offset;
      }
    }

    method writable_with_size(size: nat) returns (ok: bool)
      requires Valid()
      modifies this
      ensures Valid()
      ensures count == old(count)
      ensures ok ==> writable_length() >= size
      ensures ok ==> writable_slice_len(0) >= size
      ensures ReadableModel() == old(ReadableModel())
    {
      ok := ensure_unused_capacity(size);
      if !ok { return; }
      var n := writable_slice_len(0);
      if n < size {
        realign();
      }
      ok := true;
    }

    method update(n: nat)
      requires Valid()
      requires count + n <= |buf|
      modifies this
      ensures Valid()
      ensures count == old(count) + n
    {
      count := count + n;
    }

    method write_item_assume_capacity(item: T)
      requires Valid()
      requires writable_length() >= 1
      modifies this
      ensures Valid()
      ensures count == old(count) + 1
      ensures ReadableModel() == old(ReadableModel()) + [item]
    {
      var tail := if |buf| == 0 then 0 else (head + count) % |buf|;
      buf := buf[tail := item];
      count := count + 1;
    }

    method write_item(item: T) returns (ok: bool)
      requires Valid()
      modifies this
      ensures Valid()
      ensures ok ==> ReadableModel() == old(ReadableModel()) + [item]
      ensures ok ==> count == old(count) + 1
    {
      ok := ensure_unused_capacity(1);
      if !ok { return; }
      write_item_assume_capacity(item);
      ok := true;
    }

    method write_assume_capacity(src: seq<T>)
      requires Valid()
      requires writable_length() >= |src|
      modifies this
      ensures Valid()
      ensures ReadableModel() == old(ReadableModel()) + src
      ensures count == old(count) + |src|
      decreases |src|
    {
      if |src| == 0 {
        return;
      }
      write_item_assume_capacity(src[0]);
      write_assume_capacity(src[1..]);
    }

    method write(src: seq<T>) returns (ok: bool)
      requires Valid()
      modifies this
      ensures Valid()
      ensures ok ==> ReadableModel() == old(ReadableModel()) + src
      ensures ok ==> count == old(count) + |src|
    {
      ok := ensure_unused_capacity(|src|);
      if !ok { return; }
      write_assume_capacity(src);
      ok := true;
    }

    method rewind(n: nat)
      requires Valid()
      requires writable_length() >= n
      modifies this
      ensures Valid()
      ensures count == old(count) + n
    {
      if |buf| == 0 {
        head := 0;
      } else {
        head := (head + (|buf| - n)) % |buf|;
      }
      count := count + n;
    }

    method unget(src: seq<T>) returns (ok: bool)
      requires Valid()
      modifies this
      ensures Valid()
      ensures ok ==> ReadableModel() == src + old(ReadableModel())
    {
      ok := ensure_unused_capacity(|src|);
      if !ok { return; }
      var r := src + ReadableModel();
      buf := r + Fill(|buf| - |r|);
      head := 0;
      count := |r|;
      ok := true;
    }

    method peek_item(offset: nat) returns (item: T)
      requires Valid()
      requires offset < count
      ensures item == ReadableModel()[offset]
    {
      var index := (head + offset) % |buf|;
      item := buf[index];
    }

    method poke_item(offset: nat, item: T)
      requires Valid()
      requires offset < count
      modifies this
      ensures Valid()
      ensures ReadableModel() == old(ReadableModel())[offset := item]
    {
      var index := (head + offset) % |buf|;
      buf := buf[index := item];
    }

    method ordered_remove_item(offset: nat)
      requires Valid()
      requires offset < count
      modifies this
      ensures Valid()
      ensures ReadableModel() == old(ReadableModel())[..offset] + old(ReadableModel())[offset+1..]
      ensures count == old(count) - 1
    {
      if offset == 0 {
        discard(1);
        return;
      }
      var r := ReadableModel()[..offset] + ReadableModel()[offset+1..];
      buf := r + Fill(|buf| - |r|);
      head := 0;
      count := |r|;
    }
  }

  method SampleAssertions()
  {
    var fifo := new LinearFifo<int>.Init(0, true, true);
    var ok: bool;
    ok := fifo.write([72, 69, 76, 76, 79]);
    assert ok;
    assert fifo.readable_length() == 5;
    var s := fifo.readable_slice(0);
    assert s == [72, 69, 76, 76, 79];

    var item: int;
    ok, item := fifo.read_item();
    assert ok && item == 72;
    ok := fifo.unget([80]);
    assert ok;
    item := fifo.peek_item(0);
    assert item == 80;
    fifo.poke_item(0, 81);
    item := fifo.peek_item(0);
    assert item == 81;
    fifo.ordered_remove_item(0);
    s := fifo.readable_slice(0);
    assert s == [69, 76, 76, 79];
    var out := fifo.read(4);
    assert out == [69, 76, 76, 79];
    assert fifo.readable_length() == 0;
    fifo.reset_head_if_empty();
    assert fifo.head == 0;
    fifo.shrink(0);
    assert fifo.capacity() == 0;
  }
}

